script:
frappe.ui.form.on('Item', {
    refresh: function(frm) {
        insertDropdownInHeading(frm);

        setTimeout(function() {
            updateItemLabels(frm);
        }, 300);

        // Hide the in-form custom_select_master field (optional, keeps only one visible)
        if (frm.fields_dict.custom_select_master) {
            frm.toggle_display('custom_select_master', false);
        }

        // Disable dropdown on edit, enable on new
        if (!frm.is_new()) {
            $('#custom-master-type-select').prop('disabled', true);
        } else {
            $('#custom-master-type-select').prop('disabled', false);
        }
    },
    custom_select_master: function(frm) {
        updateItemLabels(frm);
        // keep dropdown in sync if changed by code or import
        $('#custom-master-type-select').val(frm.doc.custom_select_master);
    }
});

function insertDropdownInHeading(frm) {
    // Only add once
    if ($('#custom-master-type-select').length) return;

    // Your Master Type options (keep in sync with your field)
    const options = [
        "Finished Goods Master",
        "Fabrics Master",
        "Trims Master",
        "Accessories Master",
        "Machine Master"
    ];
    // Current value (fallback to first option)
    const current = frm.doc.custom_select_master || options[0];

    let html = `<select id="custom-master-type-select" class="form-control"
        style="width: 220px; display: inline-block; margin-left:16px;">`
        + options.map(opt => `<option value="${opt}"${opt === current ? ' selected' : ''}>${opt}</option>`).join('')
        + `</select>`;

    // Insert after the page title
    $('.page-title .title-area').append(html);

    // On change, update the DocField (triggers label update)
    $('#custom-master-type-select').on('change', function() {
        let val = $(this).val();
        if (val && val !== frm.doc.custom_select_master) {
            frm.set_value('custom_select_master', val);
        }
    });
}

function updateItemLabels(frm) {
    let masterLabel = (frm.doc.custom_select_master || $('#custom-master-type-select').val() || "Item").trim();
    let wordBoundaryRegex = /\bItem\b/gi;

    // 1. For normal fields (control-label)
    $('.frappe-control').each(function() {
        let fieldname = $(this).attr('data-fieldname');
        // skip if fieldname is missing or this is the dropdown field
        if (!fieldname || fieldname === 'custom_select_master') return;

        let $label = $(this).find('label.control-label');
        if ($label.length) {
            let orig = $label.attr('data-orig-label');
            if (!orig) {
                orig = $label.text();
                $label.attr('data-orig-label', orig);
            }
            let updated = orig;
            if (masterLabel !== "Item") {
                updated = orig.replace(wordBoundaryRegex, masterLabel);
            }
            $label.text(updated);
        }
    });

    // 2. For checkboxes (label-area span)
    $('.frappe-control .label-area').each(function() {
        let $span = $(this);
        let orig = $span.attr('data-orig-label');
        if (!orig) {
            orig = $span.text();
            $span.attr('data-orig-label', orig);
        }
        let updated = orig;
        if (masterLabel !== "Item") {
            updated = orig.replace(wordBoundaryRegex, masterLabel);
        }
        $span.text(updated);
    });

    // 3. Section headings (Section Breaks)
    $('.form-section .section-head').each(function() {
        let $sec = $(this);
        let orig = $sec.attr('data-orig-title');
        if (!orig) {
            orig = $sec.text();
            $sec.attr('data-orig-title', orig);
        }
        let updated = orig;
        if (masterLabel !== "Item") {
            updated = orig.replace(wordBoundaryRegex, masterLabel);
        }
        $sec.text(updated);
    });

    // 4. Main form title (New Item -> New Fabric Master, etc)
    $('.title-text').each(function() {
        let $title = $(this);
        let orig = $title.attr('data-orig-title');
        if (!orig) {
            orig = $title.text();
            $title.attr('data-orig-title', orig);
        }
        let updated = orig;
        if (masterLabel !== "Item") {
            updated = orig.replace(wordBoundaryRegex, masterLabel);
        }
        $title.text(updated);
    });
}
